**Tools/ApiTools.cs** â€” Tool class wrapping a REST API:

```csharp
using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a user by ID from the REST API.")]
    public async Task<string> GetUser(
        [Description("The unique user ID")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new user with the given name and email.")]
    public async Task<string> CreateUser(
        [Description("User's full name")] string name,
        [Description("User's email address")] string email,
        CancellationToken cancellationToken = default)
    {
        var payload = JsonSerializer.Serialize(new { name, email });
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/users", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}
```

